Here's a modern MSTest approach for testing your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_WhenRequestSucceeds()
    {
        var handler = new MockHttpMessageHandler("expected content", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("expected content", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenResponseIsError()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // Fails test if it hangs beyond 5s
    public async Task FetchAsync_IsCancellable()
    {
        var handler = new DelayedHttpMessageHandler(TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable mock handler
    private sealed class MockHttpMessageHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            var response = new HttpResponseMessage(status)
            {
                Content = new StringContent(content)
            };
            return Task.FromResult(response);
        }
    }

    private sealed class DelayedHttpMessageHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---------|--------|
| `async Task` return | MSTest awaits your test natively—no `GetAwaiter().GetResult()` needed |
| `[Timeout(ms)]` | Guards against hangs; works with async tests in MSTest v3+ |
| `Assert.ThrowsExceptionAsync<T>` | Proper async exception assertion |
| `CancellationToken` forwarding | Proves your method respects cancellation |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over HTTP behavior |

**MSTest v3+ note:** If using MSTest SDK (`MSTest.Sdk`), `[Timeout]` uses `CancellationToken` cooperatively via `TestContext.CancellationTokenSource`. For MSTest v4, prefer `Assert.ThrowsExactly<T>` over `ThrowsException<T>` for stricter type matching.
